#include <stdio.h>
#include <string.h>

int main() {
    const char *names[] = {"Alice","Bob","Charlie","David","Eva","John"};
    const int grades[] = {85,72,90,65,88,45};
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char query[101];
    for (int i = 0; i < T; ++i) {
        scanf("%100s", query);
        int found = 0;
        for (int j = 0; j < 6; ++j) {
            if (strcmp(query, names[j]) == 0) {
                printf("%d", grades[j]);
                found = 1;
                break;
            }
        }
        if (!found) printf("Not Found");
        if (i < T - 1) printf("\n");
    }
    return 0;
}

